<?php require_once 'app/models/Project.php'; class DashboardController{private $m;function __construct($db){$this->m=new Project($db);}function index(){requireRole(['Super Admin','Admin','School Coordinator','Campus Director','Extension Director','VP ORIES','Reviewer']);$projects=$this->m->all();$statusCounts=[];$programCounts=[];$municipalityCounts=[];foreach($projects as $p){$statusCounts[$p['status']]=($statusCounts[$p['status']]??0)+1;$programCounts[$p['program_title']]=($programCounts[$p['program_title']]??0)+1;$municipalityCounts[$p['municipality']]=($municipalityCounts[$p['municipality']]??0)+1;}$total=count($projects);include 'app/views/dashboard/index.php';}} ?>